public class Lit {
  public static float pi(){ return 3.14f; }
  public static double e(){ return 2.718281828; }
  public static long big(){ return 10000000000L; }
  public static float fzero(){ return 0.0f; }
  public static double dhalf(){ return 0.5; }
  public static long lsmall(){ return 42L; }
}
